        String fileName = scanner.next();

        // Check if the file path is within a specific directory
        File directory = new File("/path/to/secure/directory");
        File requestedFile = new File(directory, fileName);

        if (requestedFile.getCanonicalPath().startsWith(directory.getCanonicalPath())) {
